module fsm(
    input IN,
    input CLK,
    input RST,
    output MATCH
);
reg[3:0] state = 0;
reg[3:0] next_state;
reg[3:0] out;
always @(in or state) begin
    if (state==0 && in[4-1:0]==1) begin
        next_state <= 4'd1;
    end
    else begin
        next_state <= state;
    end
    if (state==1 && in[4-1:0]==0) begin
        next_state <= 4'd2;
    end
    else begin
        next_state <= state;
    end
    if (state==2 && in[4-1:0]==0) begin
        next_state <= 4'd3;
    end
    else begin
        next_state <= state;
    end
    if (state==3 && in[4-1:0]==1) begin
        next_state <= 4'd4;
    end
    else begin
        next_state <= state;
    end
    if (state==4 && in[4-1:0]==1) begin
        next_state <= 4'd5;
    end
    else begin
        next_state <= state;
    end
    if (state==5 && in[4-1:0]==0) begin
        next_state <= 4'd6;
    end
    else begin
        next_state <= state;
    end
    if (state==6 && in[4-1:0]==0) begin
        next_state <= 4'd7;
    end
    else begin
        next_state <= state;
    end
    if (state==7 && in[4-1:0]==1) begin
        next_state <= 4'd1;
    end
    else begin
        next_state <= 4'd0;
    end
end
always @(posedge clk or posedge rst) begin
    if (rst==1) begin
        state <= 4'd0;
        out <= 0;
    end
    else begin
        state <= next_state;
        out <= next_state == 4'd7 ? 1 : 0;
    end
end
assign match = out;
endmodule
